import { useEffect, useState } from "react";
import ListItem from "../../components/People/ListItem";

const Pending = (props) => {
  const [pendingRequests, setPendingRequests] = useState([]);

  useEffect(() => {
    // const fetchData = async () => {
    //   const res = await fetch("/user/pending", {
    //     headers: {
    //       Authorization: "Bearer " + props.token,
    //     },
    //   });
    //   const resData = await res.json();
    //   console.log(resData);
    // };

    const fetchData = async () => {
      try {
        const res = await fetch("/user/pending", {
          headers: {
            Authorization: "Bearer " + props.token,
          },
        });
        const resData = await res.json();
        const pendingOutgoing = resData.outgoingRequests;
        const pendingIncoming = resData.incomingRequests;

        const pending = pendingOutgoing.concat(pendingIncoming);
        setPendingRequests(pending);
      } catch (err) {
        console.log(err);
      }
    };
    fetchData();
  }, [props.token]);
  return <div></div>;
};

export default Pending;
